'use client';

import React, { useState, useEffect } from 'react';
import { useRouter } from 'next/navigation';
import {useAuth} from '../../../context/AuthContext'
import { signOut, sendEmailVerification } from 'firebase/auth';
import { httpsCallable } from 'firebase/functions';
import {functions,auth} from '../../../lib/firebaseClient'


import { Mail, Hash, Phone, ShieldCheck, ShieldAlert, Gem, Award, LogOut, Loader2 } from 'lucide-react';

// Types
interface ProfileData {
  name: string; email: string; delegateId: string; phone: string;
  points: number; solvedQuestions: number; unsolvedQuestions: number;
}
interface GetProfileResponse { success: true; profile: ProfileData; }

export default function ProfilePage() {
  const { user, loading: authLoading } = useAuth();
  const router = useRouter();
  const [profile, setProfile] = useState<ProfileData | null>(null);
  const [loading, setLoading] = useState(true);
  const [error, setError] = useState<string | null>(null);
  const [verificationSent, setVerificationSent] = useState(false);

  useEffect(() => {
    if (!authLoading) {
      if (user) {
        // User is logged in, fetch their profile
        const fetchProfile = async () => {
          try {
            const getUserProfile = httpsCallable<void, GetProfileResponse>(functions, 'getUserProfile');
            const result = await getUserProfile();
            if (result.data.success) {
              setProfile(result.data.profile);
            }
          } catch (err: any) {
            setError(err.message);
          } finally {
            setLoading(false);
          }
        };
        fetchProfile();
      } else {
        // User is not logged in, redirect
        router.push('/');
      }
    }
  }, [user, authLoading, router]);

  const handleLogout = async () => {
    await signOut(auth);
    // Redirect is handled by the auth listener in the context
  };

  const handleResendVerification = async () => {
      if (user && !user.emailVerified) {
          try {
            await sendEmailVerification(user);
            setVerificationSent(true);
            setTimeout(() => setVerificationSent(false), 30000); // Re-enable after 30s
          } catch (error) {
            setError("Failed to send verification email. Please try again later.");
          }
      }
  };

  if (authLoading || loading) {
    return <div className="min-h-screen flex items-center justify-center"><Loader2 size={48} className="animate-spin text-pink-500"/></div>;
  }

  if (error) {
     return <div className="min-h-screen flex flex-col items-center justify-center text-red-400">
       <p>Error: {error}</p>
       <button onClick={handleLogout} className="mt-4 px-4 py-2 bg-pink-600 text-white rounded-lg">Go to Login</button>
     </div>;
  }

  if (!user || !profile) {
    return null; // Should be handled by redirect in useEffect
  }

  const displayStats = { rank: 12, totalPoints: profile.points, challengesSolved: profile.solvedQuestions, challengesAttempted: profile.solvedQuestions + profile.unsolvedQuestions };
  const displayUser = { ...profile, title: "Elite Hacker" };

  return (
    <div className="min-h-screen p-4 sm:p-8 lg:p-12">
      {!user.emailVerified && (
        <div className="bg-yellow-900/50 border border-yellow-500 text-yellow-300 p-4 rounded-lg mb-8 text-center flex justify-center items-center gap-4">
            <span>Your email is not verified. Please check your inbox.</span>
            <button onClick={handleResendVerification} disabled={verificationSent} className="font-bold underline hover:text-white disabled:opacity-50 disabled:cursor-not-allowed">
                {verificationSent ? 'Sent!' : 'Resend Email'}
            </button>
        </div>
      )}

      <header className="flex justify-between items-center pb-8 border-b border-pink-500/20 mb-8">
        <h1 className="font-bold text-3xl text-pink-500 tracking-widest">USER_PROFILE</h1>
        <button onClick={handleLogout} className="font-mono text-sm flex items-center gap-2 px-3 py-1 rounded-md hover:bg-gray-800 transition-all">
            <LogOut size={16} /> Sign Out
        </button>
      </header>
       <main className="grid grid-cols-1 lg:grid-cols-12 gap-6 sm:gap-8">
            <p>Your profile UI can be pasted here and will work with `displayUser` and `displayStats`.</p>
       </main>
    </div>
  );
}